import React, { useState } from "react";
import axios from "axios";
import { motion } from "framer-motion";
import { Bar } from "react-chartjs-2";
import "chart.js/auto";

function App() {

  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [metrics, setMetrics] = useState(null);
  const [active, setActive] = useState("chat");
  const [showMetrics, setShowMetrics] = useState(false);

  const sendMessage = async () => {
    if (!input) return;

    const text = input;

    setMessages(prev => [...prev, { type: "user", text }]);
    setInput("");

    setMessages(prev => [...prev, { type: "ai", text: "Processing..." }]);

    try {
      const res = await axios.post("http://127.0.0.1:8000/ask", {
        query: text
      });

      setMessages(prev => [
        ...prev.slice(0, -1),
        { type: "ai", text: res.data?.answer || "No response" }
      ]);

      setMetrics(res.data);

    } catch {
      setMessages(prev => [
        ...prev.slice(0, -1),
        { type: "ai", text: "Server error" }
      ]);
    }
  };

  const chartData = metrics?.metrics && {
    labels: Object.keys(metrics.metrics),
    datasets: [
      {
        label: "Evaluation Metrics",
        data: Object.values(metrics.metrics),
        backgroundColor: "#3b82f6"
      }
    ]
  };

  const handleMenuClick = (item) => {
    if (item === "metrics") {
      setShowMetrics(!showMetrics); // toggle panel
    } else {
      setActive(item);
    }
  };

  return (
    <div style={{
      height: "100vh",
      display: "flex",
      flexDirection: "column",
      background: "#f8fafc",
      color: "#1e293b"
    }}>

      {/* HEADER */}
      <div style={{
        padding: "14px",
        background: "#ffffff",
        borderBottom: "2px solid #e2e8f0",
        fontWeight: "600",
        textAlign: "center",
        color: "#1e3a8a"
      }}>
        Business & Legal Multi-Agent RAG Dashboard
      </div>

      <div style={{ display: "flex", flex: 1 }}>

        {/* SIDEBAR */}
        <div style={{
          width: "230px",
          background: "#f1f5f9",
          padding: "20px",
          borderRight: "2px solid #e2e8f0"
        }}>

          <h3 style={{ marginBottom: "20px", color: "#1e3a8a" }}>Dashboard</h3>

          {["chat", "metrics", "project", "about"].map(item => (
            <div
              key={item}
              onClick={() => handleMenuClick(item)}
              style={{
                padding: "12px",
                marginBottom: "10px",
                borderRadius: "8px",
                cursor: "pointer",
                background: active === item ? "#dbeafe" : "transparent",
                color: "#1e293b",
                boxShadow: active === item ? "0 2px 6px rgba(0,0,0,0.1)" : "none"
              }}
            >
              {item === "chat" && "Chat"}
              {item === "metrics" && "Metrics Evaluation"}
              {item === "project" && "Project Details"}
              {item === "about" && "About Us"}
            </div>
          ))}

        </div>

        {/* MAIN CONTENT */}
        <div style={{ flex: 1, display: "flex" }}>

          {/* LEFT SECTION */}
          <div style={{ flex: 1, padding: "20px" }}>

            {/* CHAT */}
            {active === "chat" && (
              <div style={card}>
                <h2>Chat</h2>

                <div style={{ height: "300px", overflowY: "auto" }}>
                  {messages.map((msg, i) => (
                    <motion.div
                      key={i}
                      style={{
                        background: msg.type === "user" ? "#3b82f6" : "#e2e8f0",
                        color: msg.type === "user" ? "white" : "#1e293b",
                        padding: "10px",
                        margin: "5px",
                        borderRadius: "10px",
                        textAlign: msg.type === "user" ? "right" : "left"
                      }}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                    >
                      {msg.text}
                    </motion.div>
                  ))}
                </div>

                <div style={{ display: "flex", gap: "10px" }}>
                  <input
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="Enter your query..."
                    style={inputStyle}
                    onKeyDown={(e) => e.key === "Enter" && sendMessage()}
                  />

                  <button onClick={sendMessage} style={arrowBtn}>
                    →
                  </button>
                </div>
              </div>
            )}

            {/* PROJECT */}
            {active === "project" && (
              <div style={card}>
                <h2>Project Details</h2>
                <ul>
                  <li>Query Processing</li>
                  <li>Routing System</li>
                  <li>Retriever</li>
                  <li>Reasoning Engine</li>
                </ul>
              </div>
            )}

            {/* ABOUT */}
            {active === "about" && (
              <div style={card}>
                <h2>About Us</h2>
                <p>This system uses Multi-Agent RAG for intelligent responses.</p>
                <p>Developed by Yamini.</p>
              </div>
            )}

          </div>

          {/* RIGHT METRICS PANEL */}
          {showMetrics && (
            <div style={{
              width: "350px",
              background: "#ffffff",
              borderLeft: "2px solid #e2e8f0",
              padding: "15px",
              overflowY: "auto"
            }}>
              <h3>Metrics Evaluation</h3>

              {chartData ? (
                <>
                  <Bar data={chartData} />
                  <p><strong>Response Time:</strong> {metrics?.response_time}s</p>
                </>
              ) : (
                <p>No metrics available</p>
              )}
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

/* Styles */

const card = {
  background: "white",
  padding: "20px",
  borderRadius: "12px",
  border: "1px solid #e2e8f0"
};

const inputStyle = {
  flex: 1,
  padding: "10px",
  borderRadius: "20px",
  border: "1px solid #cbd5f5"
};

const arrowBtn = {
  background: "#3b82f6",
  color: "white",
  border: "none",
  width: "40px",
  height: "40px",
  borderRadius: "50%",
  cursor: "pointer",
  fontSize: "18px"
};

export default App;
